svg.script:
var RUNS = {
  pk26L: { label:'K2.6 · longdoc · loop: 5,236 → 7,815 — escalates; false promise on turn 1', extra:['dk26L','lk26'] },
  pk3L:  { label:'K3 · longdoc · loop: 5,666 → 1,025 — collapses; passes on turn 2', extra:['dk3L','lk3'] },
  pk3a:  { label:'K3 · enumerate: 3,038 → 1,188 → 155', extra:['ek3a'] },
  pk3b:  { label:'K3 · longdoc: 4,546 → 2,336 → 1,389', extra:['ek3b'] },
  pk3c:  { label:'K3 · build: 327 → 418 → 241 (idled — its one off-pattern run)', extra:['ek3c'] },
  pk26a: { label:'K2.6 · enumerate: 4,451 → 4,789 → 2,505', extra:['ek26a'] },
  pk26b: { label:'K2.6 · build: 3,047 → 1,863 → 1,770', extra:['ek26b'] },
  pk26c: { label:'K2.6 · longdoc: 8,365 → 361 → 1,056 (declared done on turn 2)', extra:['ek26c'] }
};
var VIEW_RUNS = [['pk26L','pk3L'], ['pk3a','pk3b','pk3c','pk26a','pk26b','pk26c'], []];
var CAPS = [
  'Same task, same loop: K3 front-loads then collapses; K2.6 holds and escalates — its turn 1 carries the false promise.',
  'No checker, no goal — K3’s decay is a trait, not a response to feedback; K2.6 keeps re-verifying.',
  '13,564 vs 6,501 reasoning tokens, one-shot, for the identical 3/3 pass.'
];
var RO = ['hover a line for exact per-turn values', 'hover a line for exact per-turn values', ''];
var view = 0, hovered = null;
function $(id){ return document.getElementById(id); }
function applyHover(){
  var ids = VIEW_RUNS[view];
  for (var i = 0; i < ids.length; i++){
    var id = ids[i], el = $(id), r = RUNS[id];
    var op = parseFloat(el.getAttribute('data-op')), w = el.getAttribute('data-w');
    if (hovered){ if (id === hovered){ op = 1; w = (parseFloat(w) + 1).toFixed(1); } else op = 0.12; }
    el.style.opacity = op;
    if (el.tagName === 'path') el.setAttribute('stroke-width', w);
    for (var k = 0; k < r.extra.length; k++){
      var ex = $(r.extra[k]);
      if (ex) ex.style.opacity = hovered ? (id === hovered ? 1 : 0.12) : (ex.getAttribute('data-op') || 1);
    }
  }
  $('ro').textContent = hovered ? RUNS[hovered].label : RO[view];
  $('ro').setAttribute('fill', hovered ? '#1b1b1a' : '#6b6b66');
  $('ro').setAttribute('font-weight', hovered ? '600' : '400');
}
function show(i){
  view = i; hovered = null;
  for (var v = 0; v < 3; v++){
    $('v'+v).setAttribute('display', v === i ? 'inline' : 'none');
    $('br'+v).setAttribute('stroke', v === i ? '#1b1b1a' : '#ececec');
    $('bx'+v).setAttribute('font-weight', v === i ? '700' : '400');
  }
  $('vcap').textContent = CAPS[i];
  applyHover();
}
var hits = document.getElementsByClassName('hit');
for (var i = 0; i < hits.length; i++)(function(h){
  h.addEventListener('pointerenter', function(){ hovered = h.getAttribute('data-run'); applyHover(); });
  h.addEventListener('pointerleave', function(){ hovered = null; applyHover(); });
})(hits[i]);
for (var b = 0; b < 3; b++)(function(b){ $('bt'+b).addEventListener('click', function(){ show(b); }); })(b);
show(0);
